+    await logger.step("verify prompt content section", async () => {
+      await expect(page.getByRole("heading", { level: 2, name: "Prompt Content" })).toBeVisible();
+      await expect(page.getByText(/Review this code thoroughly/i)).toBeVisible();
+    });
