+      await expect(page.getByText("doesn't exist or has been removed")).toBeVisible();
+    });
+
+    await logger.step("verify back link", async () => {
+      await expect(page.getByRole("button", { name: "Back to Swap Meet" })).toBeVisible();
+    });
+  });
+});

